<div class="card content-card mb-4"><div class="card-body p-4"><form method="get" action="<?= e(url('/leave/requests')); ?>" class="row g-3 align-items-end"><div class="col-lg-6"><label class="form-label">Search</label><input type="text" name="q" class="form-control" placeholder="Employee, department, leave type, or request reason..." value="<?= e((string) ($search ?? '')); ?>"></div><div class="col-md-3 col-lg-2"><label class="form-label">Status</label><select name="status" class="form-select"><option value="all">All statuses</option><?php foreach (['draft' => 'Draft', 'submitted' => 'Submitted', 'pending_manager' => 'Pending Manager', 'pending_hr' => 'Pending HR', 'approved' => 'Approved', 'rejected' => 'Rejected', 'cancelled' => 'Cancelled', 'withdrawn' => 'Withdrawn'] as $value => $label): ?><option value="<?= e($value); ?>" <?= (string) ($status ?? 'all') === $value ? 'selected' : ''; ?>><?= e($label); ?></option><?php endforeach; ?></select></div><div class="col-md-3 col-lg-2"><label class="form-label">Leave Type</label><select name="leave_type_id" class="form-select"><option value="0">All leave types</option><?php foreach (($leaveTypes ?? []) as $leaveType): ?><option value="<?= e((string) $leaveType['id']); ?>" <?= (string) ($leaveTypeId ?? 0) === (string) $leaveType['id'] ? 'selected' : ''; ?>><?= e((string) $leaveType['name']); ?></option><?php endforeach; ?></select></div><div class="col-lg-2 d-flex gap-2"><button type="submit" class="btn btn-outline-secondary w-100">Filter</button><a href="<?= e(url('/leave/requests')); ?>" class="btn btn-outline-light border w-100">Reset</a></div></form></div></div>

