fw-semibold"><?= e(number_format((float) $leaveRequest['days_requested'], 2)); ?></td><td><?php $statusValue = (string) $leaveRequest['status']; ?><span class="badge <?= in_array($statusValue, ['approved'], true) ? 'text-bg-success' : (in_array($statusValue, ['rejected', 'cancelled', 'withdrawn'], true) ? 'text-bg-danger' : 'text-bg-warning'); ?>"><?= e(ucwords(str_replace('_', ' ', $statusValue))); ?></span></td><td><?= e((string) (($leaveRequest['submitted_at'] ?? null) !== null ? $leaveRequest['submitted_at'] : $leaveRequest['created_at'])); ?></td><td class="text-end"><a href="<?= e(url('/leave/requests/' . $leaveRequest['id'])); ?>" class="btn btn-outline-secondary btn-sm">View</a></td></tr><?php endforeach; ?></tbody></table></div><?php endif; ?></div></div>